// Parse plain text file — handles tab, comma, pipe, semicolon delimiters
const binaryKey = 'file';
const binaryData = $input.first().binary?.[binaryKey];
if (!binaryData) return [{ json: { error: 'No binary data found' } }];

const text = Buffer.from(binaryData.data, 'base64').toString('utf-8');
const lines = text.split('\n').map(l => l.trim()).filter(l => l.length > 0);

if (lines.length === 0) return [];

// Auto-detect delimiter
const delimiters = [',', '\t', '|', ';'];
let bestDelimiter = ',';
let maxCols = 1;
for (const d of delimiters) {
  const count = (lines[0].split(d)).length;
  if (count > maxCols) { maxCols = count; bestDelimiter = d; }
}

if (maxCols > 1) {
  // Delimited text — treat Row 1 as headers
  const headers = lines[0].split(bestDelimiter).map(h => h.trim().replace(/^"|"$/g, ''));
  return lines.slice(1).map(line => {
    const vals = line.split(bestDelimiter).map(v => v.trim().replace(/^"|"$/g, ''));
    const row = {};
    headers.forEach((h, i) => { row[h] = vals[i] ?? ''; });
    return { json: row };
  });
} else {
  // Plain text — one row per line
  return lines.map((line, idx) => ({
    json: { Line_Number: idx + 1, Content: line }
  }));
}

// ─── STANDARD SCHEMA ────────────────────────────────────────────────
// Add column name variations your distributors use as aliases.
// The key is the canonical column name that goes into Google Sheets.
const SCHEMA = {
  "Customer_Name":  ["customer name","customer","cust name","cust","client","client name","name of customer","buyer","account name","party name","consignee"],
  "Order_ID":       ["order id","order no","order number","order#","po number","po no","purchase order","ref no","reference number","invoice no","invoice number","bill no"],
  "Product_Name":   ["product","product name","item","item name","description","goods","material","sku name","article","product description","item description"],
  "SKU_Code":       ["sku","sku code","sku#","item code","product code","article code","material code","part no","part number","barcode","upc"],
  "Quantity":       ["qty","quantity","units","unit qty","no of units","pieces","pcs","count","nos","ordered qty","order qty"],
  "Unit_Price":     ["unit price","price","rate","unit rate","cost","mrp","selling price","sp","sale price","price per unit"],
  "Amount":         ["amount","total","total amount","value","total value","net amount","gross amount","amt","subtotal","net value","invoice amount","bill amount"],
  "Order_Date":     ["order date","date","invoice date","po date","dispatch date","transaction date","bill date","sale date","booking date"],
  "Region":         ["region","zone","area","territory","location","state","city","branch"],
  "Remarks":        ["remarks","notes","comments","note","observation","info","comment","special instructions"]
};

// Build reverse alias lookup
const ALIAS_MAP = {};
for (const [canonical, aliases] of Object.entries(SCHEMA)) {
  for (const alias of aliases) {
    ALIAS_MAP[alias.toLowerCase().trim()] = canonical;
  }
}

// Character-level similarity (handles typos)
function similarity(a, b) {
  a = a.toLowerCase().trim();
  b = b.toLowerCase().trim();
  if (a === b) return 1;
  const longer  = a.length >= b.length ? a : b;
  const shorter = a.length >= b.length ? b : a;
  if (longer.length === 0) return 1;
  let matches = 0;
  for (let i = 0; i < shorter.length; i++) {
    if (longer.includes(shorter[i])) matches++;
  }
  return matches / longer.length;
}

function mapColumn(raw) {
  const cleaned = raw.toLowerCase().trim();
  if (ALIAS_MAP[cleaned]) return ALIAS_MAP[cleaned];  // exact match
  // Fuzzy match with 0.78 threshold
  let bestScore = 0, bestMatch = null;
  for (const alias of Object.keys(ALIAS_MAP)) {
    const score = similarity(cleaned, alias);
    if (score > bestScore) { bestScore = score; bestMatch = alias; }
  }
  if (bestScore >= 0.78 && bestMatch) return ALIAS_MAP[bestMatch];
  // No match — sanitise and keep original
  return raw.trim().replace(/\s+/g, '_').replace(/[^a-zA-Z0-9_]/g, '');
}

// Pull metadata from webhook body
const webhookBody = $('Webhook').first().json.body ?? {};
const distributorName = webhookBody.distributorName ?? 'Unknown';
const distributorId   = webhookBody.distributorId   ?? '';
const uploaderName    = webhookBody.uploaderName     ?? '';
const timestamp       = webhookBody.timestamp        ?? new Date().toISOString();
const fileName        = webhookBody.fileName         ?? '';

const output = [];

for (const item of $input.all()) {
  // Word/PDF extractors return { text: '...' } — wrap as Content column
  const rawRow = (item.json.text !== undefined)
    ? { Content: item.json.text }
    : item.json;

  // Remap every column header
  const mappedRow = {};
  for (const [rawCol, value] of Object.entries(rawRow)) {
    if (rawCol === '' || rawCol === null) continue;
    const canonical = mapColumn(String(rawCol));
    mappedRow[canonical] = value;
  }

  output.push({
    json: {
      Distributor:      distributorName,
      Distributor_ID:   distributorId,
      Uploaded_By:      uploaderName,
      Upload_Timestamp: timestamp,
      Source_File:      fileName,
      ...mappedRow
    }
  });
}

return output;
